if(!customElements.get('lib-loader')){class LibLoader extends HTMLElement{static get observedAttributes(){return['active','delay','size','text','overlay']}
constructor(){super();this.attachShadow({mode:'open'});this._delayTimer=null;this._isVisible=!1}
connectedCallback(){this.render();if(this.hasAttribute('active')){this.show()}}
disconnectedCallback(){this._clearTimer()}
attributeChangedCallback(name,oldValue,newValue){if(name==='active'){if(newValue!==null){this.show()}else{this.hide()}}else if(oldValue!==newValue){this.render()}}
get delay(){const d=parseInt(this.getAttribute('delay'),10);return isNaN(d)?500:d}
set delay(val){this.setAttribute('delay',String(val))}
get size(){return this.getAttribute('size')||'medium'}
set size(val){this.setAttribute('size',val);this.render()}
get text(){return this.getAttribute('text')||''}
set text(val){if(val){this.setAttribute('text',val)}else{this.removeAttribute('text')}
this.render()}
get overlay(){return this.hasAttribute('overlay')}
set overlay(val){if(val){this.setAttribute('overlay','')}else{this.removeAttribute('overlay')}
this.render()}
get active(){return this.hasAttribute('active')}
set active(val){if(val){this.setAttribute('active','')}else{this.removeAttribute('active')}}
_clearTimer(){if(this._delayTimer){clearTimeout(this._delayTimer);this._delayTimer=null}}
show(){this._clearTimer();const delayMs=this.delay;if(delayMs<=0){this.showImmediately()}else{this._delayTimer=setTimeout(()=>{this.showImmediately()},delayMs)}}
showImmediately(){this._clearTimer();this._isVisible=!0;this.classList.add('visible');this.dispatchEvent(new CustomEvent('show',{bubbles:!0}))}
hide(){this._clearTimer();this._isVisible=!1;this.classList.remove('visible');this.dispatchEvent(new CustomEvent('hide',{bubbles:!0}))}
render(){const size=this.size;const text=this.text;const overlay=this.overlay;if(this._isVisible){this.classList.add('visible')}else{this.classList.remove('visible')}
const sizes={small:{spinner:16,border:2},medium:{spinner:32,border:3},large:{spinner:48,border:4}};const s=sizes[size]||sizes.medium;this.shadowRoot.innerHTML=`
            <style>
                :host {
                    display: none;
                    position: absolute;
                    inset: 0;
                    align-items: center;
                    justify-content: center;
                }

                :host(.visible) {
                    display: flex;
                }

                :host([overlay]) {
                    z-index: 100;
                    pointer-events: none;
                }

                :host([overlay].visible) {
                    pointer-events: auto;
                }

                .loader-container {
                    display: flex;
                    flex-direction: column;
                    align-items: center;
                    justify-content: center;
                    gap: 8px;
                }

                :host([overlay]) .loader-container {
                    position: absolute;
                    inset: 0;
                    background: var(--loader-bg, rgba(255, 255, 255, 0.9));
                }

                .spinner {
                    width: ${s.spinner}px;
                    height: ${s.spinner}px;
                    border: ${s.border}px solid var(--border-color, #e0e0e0);
                    border-top-color: var(--loader-color, var(--color-info, #3F096E));
                    border-radius: 50%;
                    animation: spin 0.8s linear infinite;
                    will-change: transform;
                }

                @keyframes spin {
                    to { transform: rotate(360deg); }
                }

                .text {
                    font-size: ${size === 'small' ? '12px' : size === 'large' ? '16px' : '14px'};
                    color: var(--loader-text-color, var(--text-secondary, #666));
                    text-align: center;
                }
            </style>
            <div class="loader-container">
                <div class="spinner"></div>
                ${text ? `<div class="text">${this._escapeHtml(text)}</div>` : ''}
            </div>
        `}
_escapeHtml(str){const div=document.createElement('div');div.textContent=str;return div.innerHTML}}
customElements.define('lib-loader',LibLoader)}
